import java.util.Stack;

public class Solution {
    public static long solve(long[] weight) {
        int n = weight.length;
        int[] pge = new int[n];
        Stack<Integer> stack = new Stack<>();
        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty() && weight[stack.peek()] <= weight[i]) {
                stack.pop();
            }
            if (stack.isEmpty()) {
                pge[i] = -1;
            } else {
                pge[i] = stack.peek();
            }
            stack.push(i);
        }

        long[] dp = new long[n];
        dp[0] = 0;
        for (int i = 1; i < n; i++) {
            if (pge[i] != -1) {
                int k = pge[i];
                long prev = (k == 0) ? 0 : dp[k - 1];
                dp[i] = Math.max(dp[i - 1], prev + 1);
            } else {
                dp[i] = dp[i - 1];
            }
        }
        return dp[n - 1];
    }
}
